}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type Result = QuoteResult | ClaimResult;

export interface ScenarioResponse {
  results: Result[];
}

export interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

