export function calculatePremium(
  items: Item[],
  customer: Customer,
  isFirstPolicy: boolean
): number {
  const basePremium = getBasePremium(items);

  // Calculate total insurance value
  let totalInsuranceValue = 0;
  for (const item of items) {
    totalInsuranceValue += getInsuranceValue(item);
  }

  let premium = basePremium;

  // Apply item-specific modifiers
  for (const item of items) {
    let itemModifier = 0;

    // Cursed items: +50% surcharge
    if (item.cursed) {
      itemModifier += 0.5;
    }

    // Highly enchanted (≥ 5): +30% surcharge
    if (item.enchantment >= 5) {
      itemModifier += 0.3;
    }

    premium += basePremium * itemModifier / items.length;
  }

  // Long-standing customers (≥ 2 years): -20% discount
  if (customer.yearsWithMHPCO >= 2) {
    premium *= 0.8; // Apply 20% discount
  }

  // First insurance: +10% surcharge; later contracts: -15% discount
  if (isFirstPolicy) {
    premium *= 1.1; // +10% surcharge
  } else {
    premium *= 0.85; // -15% discount
  }

  // Add processing fee
  premium += PROCESSING_FEE;

  // Round up (in MHPCO's favor for charges)
  return Math.ceil(premium);
}

